INSERT INTO `creatives` VALUES (2,5,4,'1653262899197810','UK Study Promotion – 0 USD Fees',NULL,'Study in the UK – Pay 0 USD Service Fees','🎓 Study in the United Kingdom!\r\n\r\nParrot Canada Visa Consultant Co. Ltd is offering a LIMITED promotion for students who want to pursue:\r\n\r\n✔ Bachelor’s Degree  \r\n✔ Master’s Degree  \r\n✔ PhD Programs  \r\n\r\n✅ Service Fees Waived – Pay 0 USD!\r\n\r\nStart your journey to study in the UK with professional guidance at NO service cost.\r\n\r\n📩 Apply today and secure your future.\r\n\r\n📧 Email: infos@visaconsultantcanada.ca  \r\n📱 WhatsApp: +1 (431) 340-4830','creatives/aeJ85O3BrCD8Iow5gmSJ4JWNt6Xz2WGnSJfmisMq.jpg',NULL,'e7591ad7bcbcfa2c18f15b30a31b6849','APPLY_NOW','https://mis.visaconsultantcanada.com/student-application.php','{\"name\":\"UK Study Promotion \\u2013 0 USD Fees\",\"object_story_spec\":{\"page_id\":\"1026009140588299\",\"link_data\":{\"link\":\"https:\\/\\/visaconsultantcanada.com\",\"message\":\"\\ud83c\\udf93 Study in the United Kingdom!\\r\\n\\r\\nParrot Canada Visa Consultant Co. Ltd is offering a LIMITED promotion for students who want to pursue:\\r\\n\\r\\n\\u2714 Bachelor\\u2019s Degree  \\r\\n\\u2714 Master\\u2019s Degree  \\r\\n\\u2714 PhD Programs  \\r\\n\\r\\n\\u2705 Service Fees Waived \\u2013 Pay 0 USD!\\r\\n\\r\\nStart your journey to study in the UK with professional guidance at NO service cost.\\r\\n\\r\\n\\ud83d\\udce9 Apply today and secure your future.\\r\\n\\r\\n\\ud83d\\udce7 Email: infos@visaconsultantcanada.ca  \\r\\n\\ud83d\\udcf1 WhatsApp: +1 (431) 340-4830\",\"name\":\"Study in the UK \\u2013 Pay 0 USD Service Fees\",\"image_hash\":\"e7591ad7bcbcfa2c18f15b30a31b6849\",\"call_to_action\":{\"type\":\"LEARN_MORE\",\"value\":{\"link\":\"https:\\/\\/visaconsultantcanada.com\"}}}}}','ACTIVE','2026-03-12 09:38:09','2026-03-13 14:39:05','APPROVED',NULL,'ACTIVE','2026-03-13 14:39:05',0,0.00),(3,5,4,'1110820827851357','UK Study Promotion – French',NULL,'Étudier au Royaume-Uni 🇬🇧 – Frais de service annulés','🎓 ÉTUDIER AU ROYAUME-UNI (UK)\r\n\r\n✅ Frais de service ANNULÉS\r\n💰 Payez seulement 0 USD\r\n\r\nConsultation GRATUITE pour les étudiants souhaitant poursuivre leurs études au Royaume-Uni.\r\n\r\nProgrammes disponibles :\r\n• Licence (Bachelor)\r\n• Master\r\n• Doctorat (PhD)\r\n\r\n🌍 Une excellente opportunité pour étudier au Royaume-Uni.\r\n\r\n📧 Email : infos@visaconsultantcanada.ca\r\n📱 WhatsApp Canada : +1 (431) 340-4830\r\n📱 WhatsApp Côte d’Ivoire : +225 89 66 26 45\r\n\r\nPARROT CANADA VISA CONSULTANT CO. LTD.','/storage/creatives/LZW1pdrsz1xYSIMPKXADwVTYmygsDOWupAnGC8SH.jpg',NULL,'91b61cbf6724a3d72a12c4963ae5b974','APPLY_NOW','https://mis.visaconsultantcanada.com/student-application.php','{\"name\":\"UK Study Promotion \\u2013 French\",\"object_story_spec\":{\"page_id\":\"1026009140588299\",\"link_data\":{\"link\":\"https:\\/\\/mis.visaconsultantcanada.com\\/student-application.php\",\"message\":\"\\ud83c\\udf93 \\u00c9TUDIER AU ROYAUME-UNI (UK)\\r\\n\\r\\n\\u2705 Frais de service ANNUL\\u00c9S\\r\\n\\ud83d\\udcb0 Payez seulement 0 USD\\r\\n\\r\\nConsultation GRATUITE pour les \\u00e9tudiants souhaitant poursuivre leurs \\u00e9tudes au Royaume-Uni.\\r\\n\\r\\nProgrammes disponibles :\\r\\n\\u2022 Licence (Bachelor)\\r\\n\\u2022 Master\\r\\n\\u2022 Doctorat (PhD)\\r\\n\\r\\n\\ud83c\\udf0d Une excellente opportunit\\u00e9 pour \\u00e9tudier au Royaume-Uni.\\r\\n\\r\\n\\ud83d\\udce7 Email : infos@visaconsultantcanada.ca\\r\\n\\ud83d\\udcf1 WhatsApp Canada : +1 (431) 340-4830\\r\\n\\ud83d\\udcf1 WhatsApp C\\u00f4te d\\u2019Ivoire : +225 89 66 26 45\\r\\n\\r\\nPARROT CANADA VISA CONSULTANT CO. LTD.\",\"name\":\"\\u00c9tudier au Royaume-Uni \\ud83c\\uddec\\ud83c\\udde7 \\u2013 Frais de service annul\\u00e9s\",\"image_hash\":\"91b61cbf6724a3d72a12c4963ae5b974\",\"call_to_action\":{\"type\":\"APPLY_NOW\",\"value\":{\"link\":\"https:\\/\\/mis.visaconsultantcanada.com\\/student-application.php\"}}}}}','ACTIVE','2026-03-13 13:02:16','2026-03-14 11